class FeeCategory extends BaseFeeCategory
{
    public function save(Doctrine_Connection $conn = null)
    {
        parent::save($conn);

        $translation = new Translation();
        $translation->setTranslation('fee_category','title',parent::_get("id"), parent::_get("title"));
    }
	public function getTitle()
	{
		$translation = new Translation();
		if($translation->getTranslation('fee_category','title',$this->getId()) && $translation->getTranslation('fee_category','title',$this->getId()) != "")
        {
          	return $translation->getTranslation('fee_category','title',$this->getId());
        }
        else
        {
        	return parent::_get("title");
        }
	}
}
